import React, { useEffect, useState } from 'react';
import api from '../data/api';
import { useAuth } from '../context/AuthContext';

const s = {
  page: { padding: '2rem', maxWidth: '800px', margin: '0 auto' },
  header: { display: 'flex', alignItems: 'center', gap: '1.5rem', marginBottom: '2rem', background: '#1a1a2e', border: '1px solid #2a2a4a', borderRadius: '12px', padding: '1.5rem' },
  avatar: { width: '70px', height: '70px', borderRadius: '50%', background: '#7c6af7', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '2rem', color: '#fff', fontWeight: 700 },
  name: { fontSize: '1.4rem', fontWeight: 700, color: '#fff' },
  email: { color: '#888', fontSize: '0.9rem' },
  stats: { display: 'flex', gap: '1.5rem', marginTop: '0.75rem' },
  stat: { textAlign: 'center' },
  statVal: { fontSize: '1.3rem', fontWeight: 700, color: '#7c6af7' },
  statLabel: { color: '#888', fontSize: '0.75rem' },
  section: { marginBottom: '2rem' },
  sectionTitle: { color: '#7c6af7', fontWeight: 600, marginBottom: '1rem', fontSize: '0.95rem', textTransform: 'uppercase', letterSpacing: '0.05em' },
  progressCard: { background: '#1a1a2e', border: '1px solid #2a2a4a', borderRadius: '10px', padding: '1rem 1.25rem', marginBottom: '0.75rem' },
  progressBar: { height: '6px', background: '#2a2a4a', borderRadius: '3px', marginTop: '0.5rem', overflow: 'hidden' },
  progressFill: { height: '100%', background: '#7c6af7', borderRadius: '3px', transition: 'width 0.3s' },
  cert: { background: '#1a1a2e', border: '1px solid #f7c948', borderRadius: '10px', padding: '1rem', marginBottom: '0.75rem', display: 'flex', alignItems: 'center', gap: '1rem' },
};

export default function Profile() {
  const { user } = useAuth();
  const [progress, setProgress] = useState([]);

  useEffect(() => { api.get('/progress/all/me').then(r => setProgress(r.data)); }, []);

  return (
    <div style={s.page}>
      <div style={s.header}>
        <div style={s.avatar}>{user?.name?.[0]?.toUpperCase()}</div>
        <div>
          <div style={s.name}>{user?.name}</div>
          <div style={s.email}>{user?.email}</div>
          <div style={s.stats}>
            <div style={s.stat}><div style={s.statVal}>⭐ {user?.xp}</div><div style={s.statLabel}>XP</div></div>
            <div style={s.stat}><div style={s.statVal}>🔥 {user?.streak}</div><div style={s.statLabel}>Streak</div></div>
            <div style={s.stat}><div style={s.statVal}>{user?.certificates?.length || 0}</div><div style={s.statLabel}>Certs</div></div>
          </div>
        </div>
      </div>

      <div style={s.section}>
        <div style={s.sectionTitle}>📈 Course Progress</div>
        {progress.length === 0 && <div style={{ color: '#888' }}>No courses started yet.</div>}
        {progress.map(p => (
          <div key={p._id} style={s.progressCard}>
            <div style={{ display: 'flex', justifyContent: 'space-between' }}>
              <span style={{ color: '#e0e0e0', fontWeight: 500 }}>{p.course?.title || 'Course'}</span>
              <span style={{ color: '#7c6af7', fontWeight: 600 }}>{p.percentage}%</span>
            </div>
            <div style={s.progressBar}><div style={{ ...s.progressFill, width: `${p.percentage}%` }} /></div>
          </div>
        ))}
      </div>

      {user?.certificates?.length > 0 && (
        <div style={s.section}>
          <div style={s.sectionTitle}>🏆 Certificates</div>
          {user.certificates.map((c, i) => (
            <div key={i} style={s.cert}>
              <span style={{ fontSize: '1.5rem' }}>🎓</span>
              <div>
                <div style={{ color: '#f7c948', fontWeight: 600 }}>Course Completed</div>
                <div style={{ color: '#888', fontSize: '0.8rem' }}>Issued: {new Date(c.issuedAt).toLocaleDateString()}</div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
